return ['x-generator'=>'GlotPress/4.0.3','translation-revision-date'=>'2025-11-16 11:28:07+0000','plural-forms'=>'nplurals=3; plural=(n % 10 == 1 && n % 100 != 11) ? 0 : ((n % 10 >= 2 && n % 10 <= 4 && (n % 100 < 12 || n % 100 > 14)) ? 1 : 2);','project-id-version'=>'WordPress - 6.9.x - Administration - Network Admin','language'=>'hr','messages'=>['Users deleted.'=>'Korisnici obrisani.','Users removed from spam.'=>'Korisnici uklonjeni iz spama.','Users marked as spam.'=>'Korisnici označeni kao spam.','You can make an existing user an additional super admin by going to the Edit User profile page and checking the box to grant that privilege.'=>'Postojećeg korisnika možete pretvoriti u dodatnog super admina odlaskom u Uredi Korisnika profil stranicu i označavanjem kvadratića za dodjelu te privilegije.','The bulk action will permanently delete selected users, or mark/unmark those selected as spam. Spam users will have posts removed and will be unable to sign up again with the same email addresses.'=>'Grupne radnje će trajno obrisati odabrane korisnike, ili označiti/odznačiti one koji su selektirani kao spam. Spam korisnicima ukloniti će se postovi i neće se više moći registrirati sa istom adresom e-pošte.','You can sort the table by clicking on any of the table headings and switch between list and excerpt views by using the icons above the users list.'=>'Možete sortirati tablicu klikom na bilo koje zaglavlje i prebaciti se između pregleda liste ili sažetaka koristeći ikone iznad liste korisnika.','You can also go to the user&#8217;s profile page by clicking on the individual username.'=>'Isto tako na korisničku profil stranicu možete otići klikom na individualno korisničko ime.','Hover over any user on the list to make the edit links appear. The Edit link on the left will take you to their Edit User profile page; the Edit link on the right by any site name goes to an Edit Site screen for that site.'=>'Postavite kursor miša na bilo kojeg korisnika na listi i pojaviti će se poveznice za uređivanje. Poveznica Uredi na lijevoj strani odvesti će vas na njihovu stranicu profila; poveznica Uredi na desnoj strani pokraj bilo kojeg imena web-stranice odvesti će vas do zaslona za uređivanje te web-stranice.','This table shows all users across the network and the sites to which they are assigned.'=>'Ova tablica prikazuje sve korisnike u cijeloj mreži i web-stranice koji im pripadaju.','Warning! User cannot be modified. The user %s is a network administrator.'=>'Upozorenje! Korisnik ne može biti uređen. Korisnik %s je mrežni administrator.','Cannot add user.'=>'Ne mogu dodati korisnika.','Cannot create an empty user.'=>'Ne mogu kreirati praznog korisnika.','<a href="https://codex.wordpress.org/Network_Admin_Users_Screen">Documentation on Network Users</a>'=>'<a href="https://codex.wordpress.org/Network_Admin_Users_Screen">Dokumentacija o Mrežnim korisnicima (en)</a>','Users who are signed up to the network without a site are added as subscribers to the main or primary dashboard site, giving them profile pages to manage their accounts. These users will only see Dashboard and My Sites in the main navigation until a site is created for them.'=>'Korisnici koji su registrirani na mreži ali su bez web-stranice su dodani kao pretplatnici na glavnu ili primarnu nadzorna ploča web-stranice, dajući im stranice profila za upravljanje njihovima računima. Ovi korisnici će vidjeti samo Nadzornu ploču i Moje web-stranice u glavnoj navigaciji sve dok se ne kreira web-stranica za njih.','Add User will set up a new user account on the network and send that person an email with username and password.'=>'Dodaj korisnika će kreirati novi korisnički račun na mreži i poslati korisniku poruku e-pošte sa njegovim korisničkim imenom i lozinkom.','WordPress has been updated! Next and final step is to individually upgrade the sites in your network.'=>'WordPress je ažuriran! Slijedeći korak je individualno nadograditi web-stranice u tvojom mreži.','Next Sites'=>'Sljedeće web-stranice','If your browser does not start loading the next page automatically, click this link:'=>'Ako vaš preglednik ne počne automatski učitavati sljedeću stranicu, kliknite na ovu poveznicu:','Warning! Problem updating %1$s. Your server may not be able to connect to sites running on it. Error message: %2$s'=>'Upozorenje! Problem pri ažuriranju %1$s. Moguće je da vaš server nije u mogućnosti povezati se sa web-stranicama koje se nalaze na njemu. Poruka greške: %2$s','All done!'=>'Sve napravljeno!','<a href="https://developer.wordpress.org/advanced-administration/multisite/admin/#network-admin-updates-screen">Documentation on Upgrade Network</a>'=>'<a href="https://developer.wordpress.org/advanced-administration/multisite/admin/#network-admin-updates-screen">Dokumentacija o ažuriranju mreže</a>','If this process fails for any reason, users logging in to their sites will force the same update.'=>'Ako ovaj proces propadne iz bilo kojeg razloga, korisnici koji se prijavljuju na svoje web-stranice morati će sami proći kroz isto ažuriranje.','If a version update to core has not happened, clicking this button will not affect anything.'=>'Ako se nadogradnja jezgre na novu inačicu nije dogodila, klikom na ovo dugme neće se ništa promijeniti.','Only use this screen once you have updated to a new version of WordPress through Updates/Available Updates (via the Network Administration navigation menu or the Toolbar). Clicking the Upgrade Network button will step through each site in the network, five at a time, and make sure any database updates are applied.'=>'Ovaj zaslon upotrijebite samo kada ste nadogradili na novu inačicu WordPressa kroz Nadogradnje/Dostupne nadogradnje (putem navigacijskog izbornika Mrežna administracija ili Alatne trake). Klikom na dugme Ažurirati mrežu nadogradnja će proći kroz svaku web-stranicu u mreži, po pet odjednom, i provjeriti dali su sve nadogradnje baze podataka primijenjene.','You cannot delete a theme while it is active on the main site.'=>'Ne možete izbrisati temu dok je aktivna na glavnoj web-stranici.','%s theme will no longer be auto-updated.'=>'%s tema više neće biti automatski ažurirana.' . "\0" . '%s teme više neće biti automatski ažurirane.' . "\0" . '%s tema više neće biti automatski ažurirana.','%s theme will be auto-updated.'=>'%s tema će biti automatski ažurirana.' . "\0" . '%s teme će biti automatski ažurirano.' . "\0" . '%s tema će biti automatski ažurirano.','%s theme deleted.'=>'%s tema obrisana.' . "\0" . '%s teme obrisane.' . "\0" . '%s tema obrisano.','Themes list navigation'=>'Navigacija popisa tema','<a href="https://codex.wordpress.org/Network_Admin_Themes_Screen">Documentation on Network Themes</a>'=>'<a href="https://codex.wordpress.org/Network_Admin_Themes_Screen">Dokumentacija o Mrežnim temama (en)</a>','Themes can be enabled on a site by site basis by the network admin on the Edit Site screen (which has a Themes tab); get there via the Edit action link on the All Sites screen. Only network admins are able to install or edit themes.'=>'Mrežni admin može omogućiti teme za svaka web-stranica zasebno na zaslonu Uredi web-stranicu (koji sadrži karticu Teme);, do kojeg možete doći putem akcijske poveznice Uredi na zaslonu Sve web-stranice. Samo mrežni administratori mogu instalirati ili uređivati teme.','If the network admin disables a theme that is in use, it can still remain selected on that site. If another theme is chosen, the disabled theme will not appear in the site&#8217;s Appearance > Themes screen.'=>'Ako mrežni admin onemogući temu koja je u upotrebi, ona još uvijek može ostati aktivna na web-stranici. Ako je odabrana druga tema, onemogućena tema neće se pojaviti u zaslonu Izgled > Teme, web-stranice.','This screen enables and disables the inclusion of themes available to choose in the Appearance menu for each site. It does not activate or deactivate which theme a site is currently using.'=>'Ovaj zaslon omogućuje i onemogućuje prisutnost tema dostupnih za izbor u izborniku Izgled za svaku web-stranicu. Ne aktivira ili deaktivira temu koju web-stranica trenutno koristi.','Sorry, you are not allowed to change themes automatic update settings.'=>'Nažalost, nemate dopuštenje za promjenu postavki automatskog ažuriranja teme.','No, return me to the theme list'=>'Ne, vrati me na listu tema','Yes, delete these themes'=>'Da, obriši ove teme','Yes, delete this theme'=>'Da, obriši ovu temu','Are you sure you want to delete these themes?'=>'Jeste li sigurni da želite izbrisati ove teme?','theme%1$s by %2$s'=>'%1$s autora %2$s','You are about to remove the following themes:'=>'Ukloniti ćete sljedeće teme:','These themes may be active on other sites in the network.'=>'Ove teme bi mogle biti aktivne na drugim stranicama na mreži.','Delete Themes'=>'Obriši teme','You are about to remove the following theme:'=>'Ovime ćete izbrisati sljedeću temu:' . "\0" . 'Ovime ćete izbrisati sljedeće teme:' . "\0" . 'Ovime ćete izbrisati sljedeće teme:','This theme may be active on other sites in the network.'=>'Ova je tema možda aktivna na drugim web-stranicama u mreži.','Delete Theme'=>'Izbriši temu' . "\0" . 'Izbriši teme' . "\0" . 'Izbriši teme','Sorry, you are not allowed to delete themes for this site.'=>'Nažalost, nemate dopuštenje za brisanje tema ove web-stranice.','Sorry, you are not allowed to manage network themes.'=>'Nažalost, nemate dopuštenje za upravljanje mrežnim temama.','Site marked as spam.'=>'Web-stranica označena kao spam.','Site removed from spam.'=>'Web-stranica uklonjena iz spama.','Site flagged for deletion.'=>'Web-stranica označena za brisanje.','Site deletion flag removed.'=>'Oznaka brisanja web-stranice uklonjena.','Site unarchived.'=>'Web-stranica dearhivirana.','Site archived.'=>'Web-stranica arhivirana.','Sorry, you are not allowed to delete that site.'=>'Nažalost, nemate dopuštenje za brisanje ove web-stranice.','Site permanently deleted.'=>'Web-stranica trajno obrisana.','Sites permanently deleted.'=>'Web-stranice trajno obrisane.','Sites marked as spam.'=>'Web-stranice označene kao spam.','Sites removed from spam.'=>'Web-stranice uklonjene iz spama.','Delete these sites permanently'=>'Trajno obriši ove web-stranice','You are about to delete the following sites:'=>'Obrisati ćete slijedeće web-stranice:','Sorry, you are not allowed to delete the site %s.'=>'Nažalost, nemate dopuštenje za brisanje web-stranice %s.','Flagging a site for deletion makes the site unavailable to its users and visitors. This is a reversible action. A super admin can permanently delete the site at a later date.'=>'Označavanje web-stranice za brisanje čini je nedostupnom korisnicima i posjetiteljima. Ovo je poništiva radnja. Super administrator može trajno obrisati web-stranicu kasnije.','Archiving a site makes the site unavailable to its users and visitors. This is a reversible action.'=>'Arhiviranje web-stranice čini je nedostupnom korisnicima i posjetiteljima. Ovo je poništiva radnja.','Deleting a site is a permanent action that cannot be undone. This will delete the entire site and its uploads directory.'=>'Brisanje web-stranice je trajna radnja koja se ne može poništiti. Ovo će izbrisati cijelu web-stranicu i njezin direktorij za prijenose.','Delete this site permanently'=>'Trajno obriši ovu web-stranicu','Confirm your action'=>'Potvrdite vašu akciju','Confirm'=>'Potvrdi','Sorry, you are not allowed to change the current site.'=>'Nažalost, nemate dopuštenje za promijene na trenutnoj web-stranici.','The requested action is not valid.'=>'Zatražena akcija nije valjana.','You are about to mark the site %s as not mature.'=>'Označiti ćete da web-stranica %s nema sadržaj za odrasle.','You are about to mark the site %s as mature.'=>'Označiti ćete da web-stranica %s ima sadržaj za odrasle.','You are about to delete the site %s.'=>'Obrisati ćete site %s.','You are about to mark the site %s as spam.'=>'Označiti ćete site %s kao spam.','You are about to unspam the site %s.'=>'Ovime ćete odspamirati web-stranicu %s.','You are about to archive the site %s.'=>'Arhivirati ćete site %s.','You are about to unarchive the site %s.'=>'Dearhivirat ćete web-stranicu %s.','You are about to flag the site %s for deletion.'=>'Spremate se označiti web-stranicu %s za brisanje.','You are about to remove the deletion flag from the site %s.'=>'Spremate se ukloniti oznaku brisanja s web-stranice %s.','Sites list'=>'Popis web-stranica','Sites list navigation'=>'Navigacija popisa web-stranica','Visit to go to the front-end of the live site.'=>'Posjetite početnu stranicu kako bi ju vidjeli uživo.','Delete Permanently which is a permanent action after the confirmation screen.'=>'Obriši trajno je trajna akcija nakon potvrdnog zaslona.','Flag for Deletion, Archive, and Spam which lead to confirmation screens. These actions can be reversed later.'=>'Označi za brisanje, arhiviraj i spam vode na potvrdne zaslone. Ove akcije kasnije mogu biti opozvane.','Dashboard leads to the Dashboard for that site.'=>'Nadzorna ploča vodi prema Nadzornoj ploči za tu web-stranicu.','An Edit link to a separate Edit Site screen.'=>'Poveznica Uredi vodi na odvojeni Uredi web-stranicu zaslon.','Hovering over each site reveals seven options (three for the primary site):'=>'Prelaskom kursora preko svake web-stranice otkriva se sedam opcija (tri za primarnu web-stranicu):','This is the main table of all sites on this network. Switch between list and excerpt views by using the icons above the right side of the table.'=>'Ovo je glavna tablica svih web-stranica u ovoj mreži. Prebacite između prikaza liste i sažetka koristeći ikone iznad desne strane tablice.','Add Site takes you to the screen for adding a new site to the network. You can search for a site by Name, ID number, or IP address. Screen Options allows you to choose how many sites to display on one page.'=>'Dodaj web-stranicu vodi vas na zaslon za dodavanje nove web-stranice u mrežu. Možete tražiti web-stranicu po nazivu, ID broju ili IP adresi. Opcije zaslona omogućuju vam da odaberete koliko web-stranica želite prikazati na jednoj stranici.','A password reset link will be sent to the user via email.'=>'Poveznica za resetiranje lozinke poslati ćemo na adresu e-pošte korisnika.','Add New User'=>'Dodaj novog korisnika','Duplicated username or email address.'=>'Duplicirano korisničko ime ili adresa e-pošte.','Enter the username and email.'=>'Unesite korisničko ime i e-poštu.','User created.'=>'Korisnik kreiran.','Select a user to remove.'=>'Odaberite korisnika za uklanjanje.','Select a user to change role.'=>'Odaberite korisnika za promjenu uloge.','Enter the username of an existing user.'=>'Unesite korisničko ime postojećeg korisnika.','User could not be added to this site.'=>'Nije moguće dodati korisnika ovoj web-stranici.','User is already a member of this site.'=>'Korisnik je već član ove web-stranice.','Site users list'=>'Popis korisnika web-stranice','Site users list navigation'=>'Navigacija popisa korisnika web-stranice','Filter site users list'=>'Filtriraj popis korisnika web-stranice','Network enabled themes are not shown on this screen.'=>'Mrežne teme nisu prikazane na ovom zaslonu.','No theme selected.'=>'Nije izabrana nijedna tema.','%s theme disabled.'=>'%s tema onemogućena.' . "\0" . '%s teme onemogućene.' . "\0" . '%s tema onemogućeno.','Theme disabled.'=>'Tema onemogućena.' . "\0" . '%s teme onemogućene.' . "\0" . '%s tema onemogućeno.','%s theme enabled.'=>'%s tema omogućena.' . "\0" . '%s teme omogućene.' . "\0" . '%s tema omogućeno.','Theme enabled.'=>'Tema omogućena.' . "\0" . '%s teme omogućene.' . "\0" . '%s tema omogućeno.','Site themes list'=>'Popis tema web-stranice','Site themes list navigation'=>'Navigacija popisa tema web-stranice','Filter site themes list'=>'Filtriraj popis tema web-stranice','Sorry, you are not allowed to manage themes for this site.'=>'Nažalost, nemate dopuštenje za upravljanje temama na ovoj web-stranici.','Site options updated.'=>'Opcije web-stranice su ažurirane.','The username and a link to set the password will be mailed to this email address.'=>'Korisničko ime i poveznica za kreiranje lozinke biti će poslane na ovu adresu e-pošte.','A new user will be created if the above email address is not in the database.'=>'Novi korisnik će biti kreiran ako gore navedena adresa e-pošte nije u bazi podataka.','Admin Email'=>'Admin e-pošta','Only lowercase letters (a-z), numbers, and hyphens are allowed.'=>'Dopušteni su samo mala slova (a-z), brojevi i spojnice.','Site added. <a href="%1$s">Visit Dashboard</a> or <a href="%2$s">Edit Site</a>'=>'Web-stranica dodana. <a href="%1$s">Posjeti Nadzornu ploču</a> ili <a href="%2$s">Uredi web-stranicu</a>','There was an error creating the user.'=>'Pojavila se greška pri kreiranju korisnika.','The domain or path entered conflicts with an existing username.'=>'Unesena domena ili putanja je u konfliktu sa postojećim korisničkim imenom.','Missing email address.'=>'Nedostaje adresa e-pošte.','Missing or invalid site address.'=>'Adresa web-stranice nedostaje ili je nevažeća.','Missing site title.'=>'Nedostaje naslov web-stranice.','The following words are reserved for use by WordPress functions and cannot be used as site names: %s'=>'Navedene riječi su rezervirane za upotrebu WordPress funkcija i ne mogu biti upotrijebljene kao imena web-stranica: %s','Cannot create an empty site.'=>'Nije moguće kreirati praznu web stranicu.','If the admin email for the new site does not exist in the database, a new user will also be created.'=>'Ako admin adresa e-pošte za novu web-stranicu ne postoji u bazi podataka, novi korisnik će također biti kreiran.','This screen is for Super Admins to add new sites to the network. This is not affected by the registration settings.'=>'Ovaj zaslon je za Super admine kako bi dodali nove web-stranice u mrežu. Na ovo ne utječu registracijske postavke.','Sorry, you are not allowed to add sites to this network.'=>'Nažalost, nemate dopuštenje za dodavanje web-stranica u ovu mrežu.','sitePublic'=>'Javno','Edit Site: %s'=>'Uredi web-stranicu: %s','Site info updated.'=>'Info web-stranice ažuriran.','The requested site does not exist.'=>'Tražena web-stranica ne postoji.','Invalid site ID.'=>'Neispravan ID web-stranice.','Sorry, you are not allowed to edit this site.'=>'Nažalost, nemate dopuštenje za uređivanje ove web-stranice.','Enable administration menus'=>'Omogući administracijske izbornike','Default Language'=>'Zadani jezik','Language Settings'=>'Postavke jezika','Size in kilobytes'=>'Veličina u kilobajtima','%s KB'=>'%s KB','Max upload file size'=>'Maks. veličina datoteke za prijenos','Allowed file types. Separate types by spaces.'=>'Dozvoljene vrste zapisa. Vrste razdvojite razmacima.','Upload file types'=>'Vrste datoteka za prijenos','Limit total size of files uploaded to %s MB'=>'Limitiraj ukupnu veličinu datoteka prenesenih na %s MB','Site upload space'=>'Prostor za prijenos web-stranice','Upload Settings'=>'Postavke prijenosa','The URL for the first comment on a new site.'=>'URL prvog komentara na novoj web-stranici.','First Comment URL'=>'URL prvog komentara','The email address of the first comment author on a new site.'=>'Adresa e-pošte autora prvog komentara na novoj web-stranici.','First Comment Email'=>'E-pošta prvog komentara','The author of the first comment on a new site.'=>'Autor prvog komentara na novoj web-stranici.','First Comment Author'=>'Prvi autor komentara','The first comment on a new site.'=>'Prvi komentar na novoj web-stranici.','First Comment'=>'Prvi komentar','The first page on a new site.'=>'Prva stranica na novoj web-stranici.','First Page'=>'Prva stranica','The first post on a new site.'=>'Prvi post na novoj web-stranici.','The welcome email sent to new users.'=>'Poruka e-pošte dobrodošlice koja se šalje novim korisnicima.','Welcome User Email'=>'Poruka e-pošte dobrodošlice korisniku','The welcome email sent to new site owners.'=>'Poruka e-pošte dobrodošlice koja se šalje novim vlasnicima web-stranica.','Welcome Email'=>'Poruka e-pošte dobrodošlice','New Site Settings'=>'Postavke nove web-stranice','If you want to ban domains from site registrations. One domain per line.'=>'Ako želite zabraniti domene pri registriranju web-stranica. Jedna domena po liniji.','Banned Email Domains'=>'Zabranjene domene e-pošte','If you want to limit site registrations to certain domains. One domain per line.'=>'Ako želite limitirati registracije web-stranica na određene domene. Jedna domena po liniji.','Limited Email Registrations'=>'Ograničene registracije e-pošte','Users are not allowed to register these sites. Separate names by spaces.'=>'Korisnicima nije dopušteno registrirati ove web-stranice. Odvojite imena razmakom.','Banned Names'=>'Zabranjena imena','Allow site administrators to add new users to their site via the "Users &rarr; Add User" page'=>'Dopusti administratorima web-stranice dodavanje novih korisnika na njihovu web-stranicu putem stranice "Korisnici &rarr; Dodaj korisnika"','Add Users'=>'Dodaj korisnike','Send the network admin an email notification every time someone registers a site or user account'=>'Pošalji mrežnom adminu obavijest e-pošte svaki put kad netko registrira web-stranicu ili korisnički račun','Registration notification'=>'Registracijska obavijest','If registration is disabled, please set %1$s in %2$s to a URL you will redirect visitors to if they visit a non-existent site.'=>'Ako je registracija onemogućena, postavite %1$s u %2$s u URL na koji ćete preusmjeriti posjetitelje ako posjete ne postojeću web-stranicu.','Both sites and user accounts can be registered'=>'I web-stranice i korisnički računi mogu biti registrirani','Logged in users may register new sites'=>'Prijavljeni korisnici mogu registrirati nove web-stranice','User accounts may be registered'=>'Korisnički računi se mogu kreirati','Registration is disabled'=>'Registracija je onemogućena','Allow new registrations'=>'Dopusti nove registracije','Registration Settings'=>'Postavke registracije','There is a pending change of the network admin email to %s.'=>'Na čekanju je promjena adrese e-pošte mrežnog admina na %s.','Operational Settings'=>'Operativne postavke','<a href="https://developer.wordpress.org/advanced-administration/multisite/admin/settings/">Documentation on Network Settings</a>'=>'<a href="https://developer.wordpress.org/advanced-administration/multisite/admin/settings/">Dokumentacija o mrežnim postavkama</a>','Super admins can no longer be added on the Options screen. You must now go to the list of existing users on Network Admin > Users and click on Username or the Edit action link below that name. This goes to an Edit User page where you can check a box to grant super admin privileges.'=>'Super admini više ne mogu biti dodani na zaslonu Opcije. Sada morate otići na listu postojećih korisnika na Mrežni admin > Korisnici i kliknuti na Korisničko ime ili akcijsku poveznicu Uredi ispod imena. Ovo će vas odvesti na zaslon Uredi korisnika gdje možete označiti kvadratić kako bi odobrili super admin privilegije.','Menu setting enables/disables the plugin menus from appearing for non super admins, so that only super admins, not site admins, have access to activate plugins.'=>'Postavke izbornika omogućavaju/onemogućavaju pojavljivanje izbornika dodaci za korisnike koji nisu super admini, tako da samo super admini, ne admini web-stranice, imaju pristup aktivnim dodacima.','Upload settings control the size of the uploaded files and the amount of available upload space for each site. You can change the default value for specific sites when you edit a particular site. Allowed file types are also listed (space separated only).'=>'Postavke prijenosa kontroliraju veličinu prenesenih datoteka i količinu dostupnog prostora za prijenos za svaku web-stranicu. Možete promijeniti zadanu vrijednost za svaki pojedinu web-stranicu kada uređujete dotičnu web-stranicu. Dopuštene vrste datoteka su također izlistane (obavezno odvojeni razmakom).','New site settings are defaults applied when a new site is created in the network. These include welcome email for when a new site or user account is registered, and what&#8127;s put in the first post, page, comment, comment author, and comment URL.'=>'Postavke nove web-stranice su zadane, a one se primjenjuju kad je nova web-stranica stvorena na mreži. Ovo uključuje poruku dobrodošlice e-pošte kada je nova web-stranica ili korisnik registriran, i ono što je objavljeno u/na prvoj objavi, stranici, komentaru, autoru komentara i URL-u komentara.','Registration settings can disable/enable public signups. If you let others sign up for a site, install spam plugins. Spaces, not commas, should separate names banned as sites for this network.'=>'Postavke registracije mogu onemogućiti/omogućiti javne registracije. Ako dopustite drugima da se prijave na web-stranicu, instalirajte dodatke za neželjenu poštu. Razmaci, a ne zarezi, trebaju odvajati nazive zabranjenih web-stranica za ovu mrežu.','Operational settings has fields for the network&#8217;s name and admin email.'=>'Operativne postavke sadrže polja za ime mreže i e-poštu admina.','This screen sets and changes options for the network as a whole. The first site is the main site in the network and network options are pulled from that original site&#8217;s options.'=>'Na ovom se zaslonu postavljaju i mijenjaju opcije za mrežu u cjelini. Prva web-stranica je glavna u mreži i mrežne opcije su kopirane od opcija te originalne web-stranice.','Network Settings'=>'Mrežne postavke','Installed Themes'=>'Instalirane teme','Add Site'=>'Dodaj web-stranicu','All Sites'=>'Sve web-stranice','Upgrade Network'=>'Ažurirati mrežu','Updates'=>'Ažuriranje','<a href="https://developer.wordpress.org/advanced-administration/multisite/admin/">Documentation on the Network Admin</a>'=>'<a href="https://developer.wordpress.org/advanced-administration/multisite/admin/">Dokumentacija o mrežnom adminu</a>','Quick Tasks'=>'Brzi zadaci','To search for a site, <strong>enter the path or domain</strong>.'=>'Za pretragu stranica <strong>upišite putanju ili domenu</strong>.','To search for a user, <strong>enter an email address or username</strong>. Use a wildcard to search for a partial username, such as user&#42;.'=>'Za pretragu korisnika <strong>upišite adresu e-pošte ili korisničko ime</strong>. Koristite višeznačnik (*) u pretrazi za djelomična korisnička imena, kao npr. user&#42;.','To search for a user or site, use the search boxes.'=>'Za pretragu korisnika ili web-stranice, koristite polja za pretraživanje.','To add a new site, <strong>click Create a New Site</strong>.'=>'Za dodavanje nove web-stranice kliknite na <strong>Kreiraj novu web-stranicu</strong>.','To add a new user, <strong>click Create a New User</strong>.'=>'Za dodavanje novog korisnika kliknite na <strong>Kreiraj novog korisnika</strong>.','The Right Now widget on this screen provides current user and site counts on your network.'=>'Widget trenutno na ovom zaslonu pruža pregled broja korisnika i web-stranica na vašoj mreži.','Modify global network settings'=>'Modificiraj globalne mrežne postavke','Update your network'=>'Ažuriraj svoju mrežu','Install and activate themes or plugins'=>'Instaliraj i aktiviraj teme ili dodatke','Add and manage sites or users'=>'Dodaj i upravljaj web-stranicama ili korisnicama','From here you can:'=>'Odavde možete:','Welcome to your Network Admin. This area of the Administration Screens is used for managing all aspects of your Multisite Network.'=>'Dobrodošli u vaš Mrežni admin. Ovo područje Administratorskih zaslona se koristi za upravljanje svih aspekata vaše Multisite mreže.','Network'=>'Mreža','<a href="https://wordpress.org/documentation/article/tools-network-screen/">Documentation on the Network Screen</a>'=>'<a href="https://wordpress.org/documentation/article/tools-network-screen/">Dokumentacija o mrežnom zaslonu</a>','<a href="https://developer.wordpress.org/advanced-administration/multisite/create-network/">Documentation on Creating a Network</a>'=>'<a href="https://developer.wordpress.org/advanced-administration/multisite/create-network/">Dokumentacija o kreiranju mreže</a>','The choice of subdirectory sites is disabled if this setup is more than a month old because of permalink problems with &#8220;/blog/&#8221; from the main site. This disabling will be addressed in a future version.'=>'Izbor poddirektorij web-stranica je onemogućen ako je ova instalacija stara više od mjesec dana zbog problema stalnih veza sa &#8220;/blogom/&#8221; sa glavne web-stranice. O ovom onemogućavanju pobrinuti ćemo se uskoro u budućim inačicama.','Once you add this code and refresh your browser, multisite should be enabled. This screen, now in the Network Admin navigation menu, will keep an archive of the added code. You can toggle between Network Admin and Site Admin by clicking on the Network Admin or an individual site name under the My Sites dropdown in the Toolbar.'=>'Jednom kada dodate ovaj kod i osvježite vaš preglednik, multisite bi trebao biti omogućen. Ovaj zaslon, sada u Mrežni admin navigacijskom izborniku, čuvati će arhivu dodanog koda. Možete prebacivati između Mrežni admin i Admin stranice klikom na Mrežni admin ili svako individualno ime web-stranice u padajućem izborniku Moje web-stranice u Alatnoj traci.','Add the designated lines of code to wp-config.php (just before <code>/*...stop editing...*/</code>) and <code>.htaccess</code> (replacing the existing WordPress rules).'=>'Dodajte određene linije koda u wp-config.php (prije <code>/*...ne morate više ništa mijenjati...*/</code>) i <code>.htaccess</code> (zamjenjujuću postojeća WordPress pravila).','The next screen for Network Setup will give you individually-generated lines of code to add to your wp-config.php and .htaccess files. Make sure the settings of your FTP client make files starting with a dot visible, so that you can find .htaccess; you may have to create this file if it really is not there. Make backup copies of those two files.'=>'Sljedeći zaslon za Postavljanje mreže dati će vam individualno-generirane linije koda koje trebate dodati u vaše wp-config.php i .htaccess datoteke. Provjerite da postavke vašeg FTP klijenta omogućuju vidljivost datoteka koje počinju sa točkom, tako da možete pronaći .htaccess; možda ćete morati kreirati ovu datoteku ako već ne postoji. Napravite backup kopije ove dvije datoteke.','Choose subdomains or subdirectories; this can only be switched afterwards by reconfiguring your installation. Fill out the network details, and click Install. If this does not work, you may have to add a wildcard DNS record (for subdomains) or change to another setting in Permalinks (for subdirectories).'=>'Izaberite poddomene ili poddirektorije; ovo može biti promijenjeno poslije samo rekonfiguracijom vaše instalacije. Popunite detalje o mreži, i kliknite instaliraj. Ako ovo ne bude funkcioniralo, možda ćete morati dodati * DNS zapis (za poddomene) ili promijeniti druge postavke u sekciji Stalna veza (za poddirektorije).','This screen allows you to configure a network as having subdomains (<code>site1.example.com</code>) or subdirectories (<code>example.com/site1</code>). Subdomains require wildcard subdomains to be enabled in Apache and DNS records, if your host allows it.'=>'Ovaj zaslon vam omogućuje da konfigurirate mrežu da ima poddomene (<code>site1.primjer.com</code>) ili poddirektorije (<code>primjer.com/site1</code>). Poddomene zahtijevaju da * poddomene budu omogućene u Apache i DNS zapisima, ako vaš poslužitelj to dopušta.','Create a Network of WordPress Sites'=>'Kreiraj mrežu WordPress web-stranica','You must define the %1$s constant as true in your %2$s file to allow creation of a Network.'=>'U datoteci %2$s morate definirati %1$s konstantu kao true, kako bi omogućili kreiranje Mreže.','The Network creation panel is not for WordPress MU networks.'=>'Ploča Kreiranje mreže nije za WordPress MU mreže.','Once you complete these steps, your network is enabled and configured. You will have to log in again.'=>'Kad dovršite ove korake, vaša mreža će biti aktivirana i konfigurirana. Ponovno ćete se morati prijaviti.','https://developer.wordpress.org/advanced-administration/server/web-server/nginx/'=>'https://developer.wordpress.org/advanced-administration/server/web-server/nginx/','It seems your network is running with Nginx web server. <a href="%s">Learn more about further configuration</a>.'=>'Izgleda da vašu mrežu pogoni Nginx web poslužitelj. <a href="%s">Saznajte više o daljnjoj konfiguraciji</a>.','Add the following to your %1$s file in %2$s, <strong>replacing</strong> other WordPress rules:'=>'Dodajte sljedeće u vašu %1$s datoteku u %2$s, <strong>zamjenjujući</strong> druga WordPress pravila:','Network configuration authentication keys'=>'Autentifikacijski ključevi mrežne konfiguracije','To make your installation more secure, you should also add:'=>'Kako bi instalaciju učinili sigurnijom, dodajte i:','These unique authentication keys are also missing from your %s file.'=>'Iz %s datoteke također nedostaju i ovi jedinstveni autentifikacijski ključevi.','This unique authentication key is also missing from your %s file.'=>'Iz %s datoteke također nedostaje i jedinstveni autentifikacijski ključ.','Network configuration rules for %s'=>'Pravila mrežne konfiguracije za %s','That&#8217;s all, stop editing! Happy publishing.'=>'To je sve, ne morate više ništa mijenjati! Sretno objavljivanje.','Add the following to your %1$s file in %2$s <strong>above</strong> the line reading %3$s:'=>'Dodajte sljedeće u svoju %1$s datoteku u %2$s <strong>iznad</strong> retka u kojem piše %3$s:','You should back up your existing %s file.'=>'Trebali biste izraditi sigurnosnu kopiju postojeće datoteke %s.','You should back up your existing %1$s and %2$s files.'=>'Trebali biste izraditi sigurnosnu kopiju postojećih datoteka %1$s i %2$s.','Complete the following steps to enable the features for creating a network of sites.'=>'Dovršite sljedeće korake kako bi aktivirali mogućnosti za kreiranje mreže web-stranica.','Enabling the Network'=>'Aktiviranje Mreže','Please complete the configuration steps. To create a new network, you will need to empty or remove the network database tables.'=>'Dovršite konfiguracijske korake. Za kreiranje nove mreže morati ćete isprazniti ili ukloniti tablice baze podataka od mreže.','An existing WordPress network was detected.'=>'Detektirana je postojeća WordPress mreža.','The original configuration steps are shown here for reference.'=>'Ovdje su prikazani originalni konfiguracijski koraci za referencu.','Your email address.'=>'Vaša adresa e-pošte.','Network Admin Email'=>'E-pošta mrežnog admina','What would you like to call your network?'=>'Kako želite nazvati vašu mrežu?','Network Title'=>'Mrežni naslov','Because your installation is not new, the sites in your WordPress network must use sub-domains.'=>'Zato što vaša instalacija nije nova, web-stranice u vašoj WordPress mreži moraju koristiti poddomene.','Sub-domain Installation'=>'Pod-domena instalacija','Because your installation is in a directory, the sites in your WordPress network must use sub-directories.'=>'Zato što je vaša instalacija u mapi, web-stranice u vašoj WordPress mreži moraju koristiti podmape.','The main site in a sub-directory installation will need to use a modified permalink structure, potentially breaking existing links.'=>'Glavna web-stranica u instalaciji u podmapi morati će koristiti prilagođenu strukturu stalnih veza, potencijalno kidajući postojeću strukturu stalnih veza.','Because you are using %1$s, the sites in your WordPress network must use sub-directories. Consider using %2$s if you wish to use sub-domains.'=>'Zato jer koristite %1$s, web-stranice u vašoj WordPress mreži moraju koristiti pod-direktorije. Razmislite o korištenju %2$s ako želite koristiti pod-domene.','Sub-directory Installation'=>'Pod-direktorij instalacija','Network Details'=>'Detalji o Mreži','The internet address of your network will be %s.'=>'Internet adresa vaše mreže biti će %s.','You should consider changing your site domain to %1$s before enabling the network feature. It will still be possible to visit your site using the %3$s prefix with an address like %2$s but any links will not have the %3$s prefix.'=>'Prije aktivacije mrežne mogućnosti preporuča se promjena domene vaše web-stranice u %1$s. I dalje će biti moguće posjetiti vašu web-stranicu koristeći %3$s prefiks s adresom kao što je %2$s, ali ostale poveznice neće imati %3$s prefiks.','Server Address'=>'Adresa poslužitelja','Subdirectory networks may not be fully compatible with custom wp-content directories.'=>'Moguće je da mreže sa podmapama neće biti potpuno kompatibilne sa prilagođenim wp-content mapama.','subdirectory exampleslike <code>%1$s/site1</code> and <code>%1$s/site2</code>'=>'kao <code>%1$s/site1</code> i <code>%1$s/site2</code>','Sub-directories'=>'Podmape','subdomain exampleslike <code>site1.%1$s</code> and <code>site2.%1$s</code>'=>'kao <code>site1.%1$s</code> i <code>site2.%1$s</code>','Sub-domains'=>'Poddomene','You will need a wildcard DNS record if you are going to use the virtual host (sub-domain) functionality.'=>'Ako ćete upotrebljavati virtualni poslužitelj (poddomenu), morat ćete koristiti DNS zapis sa zamjenskim znakom (wildcard DNS record).','You cannot change this later.'=>'Ovo kasnije ne možete promijeniti.','Please choose whether you would like sites in your WordPress network to use sub-domains or sub-directories.'=>'Molim izaberite da li želite da web-stranice u vašoj WordPress mreži koriste pod-domene, ili pod-direktorije.','Addresses of Sites in your Network'=>'Adrese web-stranica u vašoj Mreži','If %1$s is disabled, ask your administrator to enable that module, or look at the <a href="%2$s">Apache documentation</a> or <a href="%3$s">elsewhere</a> for help setting it up.'=>'Ako je %1$s onemogućen, pitajte svog administratora da omogući taj modul, ili potraži<a href="%2$s">Apache dokumentacija (en)</a> ili <a href="%3$s">negdje drugdje</a> za pomoć u postavljanju.','It looks like the Apache %s module is not installed.'=>'Izgleda da Apache %s modul nije instaliran.','Please make sure the Apache %s module is installed as it will be used at the end of this installation.'=>'Molim provjerite da je Apache %s modul instaliran jer će biti korišten na kraju ove instalacije.','Fill in the information below and you&#8217;ll be on your way to creating a network of WordPress sites. Configuration files will be created in the next step.'=>'Ispod unesite potrebne informacije, i započeti ćete sa kreiranjem mreže WordPress web-stranica. U sljedećem koraku kreirati ćemo konfiguracijske datoteke.','Welcome to the Network installation process!'=>'Dobro došli u instalacijski proces za Mrežu!','%s Sites'=>'%s web-stranica','The network could not be created.'=>'Mrežu nije moguće stvoriti.','Once the network is created, you may reactivate your plugins.'=>'Nakon što se mreža kreira, možete aktivirati dodatke.','Please <a href="%s">deactivate your plugins</a> before enabling the Network feature.'=>'<a href="%s">Deaktivirajte dodatke</a> prije aktiviranja Mrežne opcije.','The constant %s cannot be defined when creating a network.'=>'Nije moguće definirati konstantu %s pri kreiranju mreže.','Table ordered by User Registered Date.'=>'Tablice je poredana po datumu registracije korisnika.','userRegistered'=>'Registriran','Super Admin <span class="count">(%s)</span>'=>'Super admin <span class="count">(%s)</span>' . "\0" . 'Super admina <span class="count">(%s)</span>' . "\0" . 'Super admina <span class="count">(%s)</span>','userNot spam'=>'Nije spam','userMark as spam'=>'Označi kao spam','Active Child Theme'=>'Aktivna podtema','Child theme of %s'=>'Pod-tema od %s','Visit Theme Site'=>'Posjeti web-stranicu teme','Visit theme site for %s'=>'Otvori web-stranicu za temu %s','Broken Theme:'=>'Oštećena tema:','Network Disable %s'=>'Deaktiviraj na mreži %s','Disable %s'=>'Deaktiviraj %s','Network Enable %s'=>'Aktiviraj na mreži %s','Enable %s'=>'Aktiviraj %s','Network Disable'=>'Mreža onemogućena','themesBroken <span class="count">(%s)</span>'=>'Oštećena <span class="count">(%s)</span>' . "\0" . 'Oštećene <span class="count">(%s)</span>' . "\0" . 'Oštećeno <span class="count">(%s)</span>','themesUpdate Available <span class="count">(%s)</span>'=>'Dostupno ažuriranje <span class="count">(%s)</span>' . "\0" . 'Dostupna ažuriranja <span class="count">(%s)</span>' . "\0" . 'Dostupno ažuriranja <span class="count">(%s)</span>','themesDisabled <span class="count">(%s)</span>'=>'Onemogućena <span class="count">(%s)</span>' . "\0" . 'Onemogućene <span class="count">(%s)</span>' . "\0" . 'Onemogućeno <span class="count">(%s)</span>','themesEnabled <span class="count">(%s)</span>'=>'Omogućena <span class="count">(%s)</span>' . "\0" . 'Omogućene <span class="count">(%s)</span>' . "\0" . 'Omogućeno <span class="count">(%s)</span>','themesAll <span class="count">(%s)</span>'=>'Sva <span class="count">(%s)</span>' . "\0" . 'Sve <span class="count">(%s)</span>' . "\0" . 'Sve <span class="count">(%s)</span>','Table ordered by Theme Name.'=>'Tablice je poredana po imenu teme.','No themes are currently available.'=>'Trenutno nema dostupnih tema.','No themes found.'=>'Nije pronađena nijedan tema.','siteNot Spam'=>'Nije spam','verb; siteArchive'=>'Arhiviraj','Unarchive'=>'Dearhiviraj','Flag for Deletion'=>'Oznaka za brisanje','siteRemove Deletion Flag'=>'Ukloni oznaku za brisanje','Main'=>'Glavna','Never'=>'Nikad','Y/m/d g:i:s a'=>'d.m.Y. H:i:s','%1$s &#8211; %2$s'=>'%1$s &#8211; %2$s','Table ordered by Site Registered Date.'=>'Tablice je poredana po datumu registracije web-stranice.','Table ordered by Last Updated.'=>'Tablice je poredana po najnovijem ažuriranju.','Table ordered by Site Path.'=>'Tablice je poredana po putanji web-stranice.','Path'=>'Putanja','Table ordered by Site Domain Name.'=>'Tablice je poredana po imenu domene web-stranice.','Domain'=>'domena','siteRegistered'=>'Registrirano','Last Updated'=>'Zadnji put ažurirano','siteNot spam'=>'Nije spam','siteMark as spam'=>'Označi kao spam','Flagged for Deletion <span class="count">(%s)</span>'=>'Označena za brisanje <span class="count">(%s)</span>' . "\0" . 'Označene za brisanje <span class="count">(%s)</span>' . "\0" . 'Označenih za brisanje <span class="count">(%s)</span>','sitesSpam <span class="count">(%s)</span>'=>'Spam <span class="count">(%s)</span>' . "\0" . 'Spam <span class="count">(%s)</span>' . "\0" . 'Spam <span class="count">(%s)</span>','Mature <span class="count">(%s)</span>'=>'Zrela <span class="count">(%s)</span>' . "\0" . 'Zrela <span class="count">(%s)</span>' . "\0" . 'Zrela <span class="count">(%s)</span>','Archived <span class="count">(%s)</span>'=>'Arhivirana <span class="count">(%s)</span>' . "\0" . 'Arhivirana <span class="count">(%s)</span>' . "\0" . 'Arhivirano <span class="count">(%s)</span>','Public <span class="count">(%s)</span>'=>'Javna <span class="count">(%s)</span>' . "\0" . 'Javne <span class="count">(%1$s)</span>' . "\0" . 'Javnih <span class="count">(%1$s)</span>','sitesAll <span class="count">(%s)</span>'=>'Sva <span class="count">(%s)</span>' . "\0" . 'Sve <span class="count">(%s)</span>' . "\0" . 'Svih <span class="count">(%s)</span>','No sites found.'=>'Nije pronađena ni jedna web-stranica.','Mature'=>'Sadržaj za odrasle','Flagged for Deletion'=>'Označeno za brisanje','siteSpam'=>'Spam','Archived'=>'Arhivirano']];